import { readFileSync, writeFileSync } from "node:fs";
import {
  S3Client,
  PutObjectCommand,
  ListObjectsV2Command,
  DeleteObjectsCommand,
  DeleteBucketCommand,
} from "@aws-sdk/client-s3";
import { checkpoint, restore } from "@tigrisdata/agent-kit";

const ENDPOINT = "REDACTED";
const REGION = "REDACTED";

function normalizeBucketName(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9.-]/g, "-");
}

async function emptyAndDeleteBucket(s3: S3Client, bucket: string): Promise<void> {
  let continuationToken: string | undefined = undefined;
  do {
    const listed = await s3.send(
      new ListObjectsV2Command({
        Bucket: bucket,
        ContinuationToken: continuationToken,
      })
    );
    const objects = listed.Contents ?? [];
    if (objects.length > 0) {
      await s3.send(
        new DeleteObjectsCommand({
          Bucket: bucket,
          Delete: {
            Objects: objects
              .filter((o) => o.Key !== undefined)
              .map((o) => ({ Key: o.Key! })),
          },
        })
      );
    }
    continuationToken = listed.IsTruncated ? listed.NextContinuationToken : undefined;
  } while (continuationToken);

  await s3.send(new DeleteBucketCommand({ Bucket: bucket }));
}

async function main() {
  const trialId = readFileSync("/logs/artifacts/trial_id", "utf8").trim();
  const bucketName = normalizeBucketName(`harbor-awscli-${trialId}`);
  console.log(`Using bucket: ${bucketName}`);

  const accessKeyId = process.env.TIGRIS_STORAGE_ACCESS_KEY_ID;
  const secretAccessKey = process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY;
  if (!accessKeyId || !secretAccessKey) {
    throw new Error(
      "Missing TIGRIS_STORAGE_ACCESS_KEY_ID or TIGRIS_STORAGE_SECRET_ACCESS_KEY"
    );
  }

  const s3 = new S3Client({
    region: REGION,
    endpoint: ENDPOINT,
    credentials: { accessKeyId, secretAccessKey },
    forcePathStyle: false,
  });

  // Step 1: Upload v1
  console.log("Uploading v1.txt with body version=1...");
  await s3.send(
    new PutObjectCommand({
      Bucket: bucketName,
      Key: "v1.txt",
      Body: "version=1",
      ContentType: "text/plain; charset=utf-8",
    })
  );

  // Step 2: Checkpoint
  console.log("Creating checkpoint 'before-mutation'...");
  const { data: ckpt, error: ckptError } = await checkpoint(bucketName, {
    name: "before-mutation",
  });
  if (ckptError || !ckpt) {
    throw new Error(`checkpoint failed: ${ckptError?.message ?? "unknown"}`);
  }
  console.log(`Snapshot created: ${ckpt.snapshotId}`);

  // Step 3: Mutate
  console.log("Uploading v1.txt with body version=2 (mutation)...");
  await s3.send(
    new PutObjectCommand({
      Bucket: bucketName,
      Key: "v1.txt",
      Body: "version=2",
      ContentType: "text/plain; charset=utf-8",
    })
  );

  // Step 4: Restore into fork
  console.log("Restoring checkpoint into fork 'rollback-recovery'...");
  const { data: restored, error: restoreError } = await restore(
    bucketName,
    ckpt.snapshotId,
    { forkName: "rollback-recovery" }
  );
  if (restoreError || !restored) {
    throw new Error(`restore failed: ${restoreError?.message ?? "unknown"}`);
  }
  console.log(`Recovery bucket: ${restored.bucket}`);

  writeFileSync(
    "/home/user/chained-ckpt/recovery.json",
    JSON.stringify({ recoveryBucket: restored.bucket })
  );

  // Step 5: Teardown recovery fork bucket
  console.log(`Tearing down recovery bucket ${restored.bucket}...`);
  await emptyAndDeleteBucket(s3, restored.bucket);
  console.log("Recovery fork bucket deleted.");

  console.log("Done.");
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

