    body: bodyStr,
  };
  const signed: any = await signer.sign(req as any);
  const resp = await fetch(url.toString(), {
    method: "PATCH",
    headers: signed.headers,
    body: bodyStr,
  });
  return { status: resp.status, body: await resp.text() };
