const secretAccessKey = process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY!;

async function patch(body: any, headers: Record<string,string> = {}) {
  const bodyStr = JSON.stringify(body);
  const url = new URL(`REDACTED/${bucketName}`);
  const signer = new SignatureV4({
    credentials: { accessKeyId, secretAccessKey },
    region: "REDACTED", service: "s3", sha256: Sha256, uriEscapePath: false,
  });
  const signed: any = await signer.sign({
    method: "PATCH", protocol: url.protocol, hostname: url.hostname,
    path: url.pathname, headers: { "Content-Type": "application/json", host: url.host, ...headers }, body: bodyStr,
  } as any);
  const resp = await fetch(url.toString(), { method: "PATCH", headers: signed.headers, body: bodyStr });
  return { status: resp.status, body: await resp.text() };
}

// Try PUT with snapshot header
async function putBucket() {
  const url = new URL(`REDACTED/${bucketName}`);
  const signer = new SignatureV4({
    credentials: { accessKeyId, secretAccessKey },
    region: "REDACTED", service: "s3", sha256: Sha256, uriEscapePath: false,
  });
