    method: "PUT", protocol: url.protocol, hostname: url.hostname,
    path: url.pathname, headers: { host: url.host, "X-Tigris-Enable-Snapshot": "true" }, body: "",
  } as any);
  const resp = await fetch(url.toString(), { method: "PUT", headers: signed.headers });
  return { status: resp.status, body: await resp.text() };
}

